#ifdef __cplusplus
extern "C" {
#endif

#include <math.h>
#include <omp.h>

#include "./main.h"
#include "./kernel/kernel_cpu.h"

void kernel_cpu(par_str par,
                dim_str dim,
                box_str* box,
                FOUR_VECTOR* rv,
                fp* qv,
                FOUR_VECTOR* fv)
{
    fp a2 = 2 * par.alpha * par.alpha;

    #pragma omp parallel for schedule(static) num_threads(dim.cores_arg)
    for (long bx = 0; bx < dim.number_boxes; bx++) {
        long first_i = box[bx].offset;

        for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            FOUR_VECTOR rA = rv[first_i + i];
            FOUR_VECTOR fA = fv[first_i + i];

            for (int k = 0; k < (1 + box[bx].nn); k++) {
                int pointer;
                if (k == 0) {
                    pointer = (int)bx;
                } else {
                    pointer = box[bx].nei[k - 1].number;
                }

                long first_j = box[pointer].offset;

                for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                    FOUR_VECTOR rB = rv[first_j + j];
                    fp qB = qv[first_j + j];
                    THREE_VECTOR d;
                    fp r2;
                    fp u2;
                    fp vij;
                    fp fs;
                    fp fxij;
                    fp fyij;
                    fp fzij;

                    r2 = rA.v + rB.v - DOT(rA, rB);
                    u2 = a2 * r2;
                    vij = exp(-u2);
                    fs = 2 * vij;

                    d.x = rA.x - rB.x;
                    fxij = fs * d.x;
                    d.y = rA.y - rB.y;
                    fyij = fs * d.y;
                    d.z = rA.z - rB.z;
                    fzij = fs * d.z;

                    fA.v += qB * vij;
                    fA.x += qB * fxij;
                    fA.y += qB * fyij;
                    fA.z += qB * fzij;
                }
            }

            fv[first_i + i] = fA;
        }
    }
}

#ifdef __cplusplus
}
#endif
